tool_input.script:
export const meta = {
  name: 'nabledge-6-qa',
  description: 'QA workflow: semantic search for OAuth2/OpenID Connect in Nablarch',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for OAuth2/OIDC' },
    { title: 'Read Sections', detail: 'Read selected sections' },
    { title: 'Generate Answer', detail: 'Generate Japanese answer' },
  ],
}

const SKILL_DIR = '/home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6'
const KNOWLEDGE_DIR = `${SKILL_DIR}/knowledge`
const QUERY = 'NablarchでOAuth2やOpenID Connectによる認証を実装したい。Nablarchにその仕組みは組み込まれているか？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）'

// Step 3: Semantic search
phase('Semantic Search')
const searchResult = await agent(`
You are executing semantic search over Nablarch knowledge files.

## Task
Search the knowledge files to find sections relevant to this query:
"${QUERY}"

## Knowledge Directory
${KNOWLEDGE_DIR}

## Semantic Search Workflow
Execute the semantic search workflow at: ${SKILL_DIR}/workflows/semantic-search.md

The workflow instructs you to:
1. Read the index file to find candidate pages
2. Score pages for relevance
3. Read and score sections within relevant pages
4. Return selected_sections array

## Index File
Read ${SKILL_DIR}/knowledge/index.json first to get the list of available knowledge files.

Then for each candidate page, read the page and evaluate relevance to the query.

Focus on:
- OAuth2, OpenID Connect, OIDC authentication
- Web application security
- Authentication/authorization in Nablarch web apps
- Spring Security integration (if any)
- External authentication providers

## Output Format (JSON only, no other text)
{
  "selected_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why skipped>"}
  ],
  "selected_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "excluded_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "reason": "<why skipped>"}
  ]
}
`, { label: 'semantic-search', schema: {
  type: 'object',
  properties: {
    selected_pages: { type: 'array', items: { type: 'object', properties: { path: { type: 'string' }, reason: { type: 'string' } }, required: ['path', 'reason'] } },
    excluded_pages: { type: 'array', items: { type: 'object', properties: { path: { type: 'string' }, reason: { type: 'string' } }, required: ['path', 'reason'] } },
    selected_sections: { type: 'array', items: { type: 'object', properties: { file: { type: 'string' }, section_id: { type: 'string' }, relevance: { type: 'string' }, reason: { type: 'string' } }, required: ['file', 'section_id', 'relevance', 'reason'] } },
    excluded_sections: { type: 'array', items: { type: 'object', properties: { file: { type: 'string' }, section_id: { type: 'string' }, reason: { type: 'string' } }, required: ['file', 'section_id', 'reason'] } }
  },
  required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
}})

log(`Semantic search complete. Selected ${searchResult.selected_sections.length} sections from ${searchResult.selected_pages.length} pages.`)

// Step 4: Read sections
phase('Read Sections')
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high').slice(0, 10)
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial').slice(0, Math.max(0, 10 - highSections.length))
const sectionsToRead = [...highSections, ...partialSections]

let sectionsContent = ''
let readSections = []

if (sectionsToRead.length > 0) {
  const args = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')
  readSections = sectionsToRead.map(s => `${s.file}:${s.section_id}`)

  const readResult = await agent(`
Run this bash command and return the complete output verbatim:

\`\`\`bash
bash ${SKILL_DIR}/scripts/read-sections.sh ${args}
\`\`\`

Return only the raw output of the command, nothing else.
`, { label: 'read-sections' })

  sectionsContent = readResult
} else {
  sectionsContent = ''
}

log(`Read ${sectionsToRead.length} sections.`)

// Step 5+6+7: Generate and verify answer
phase('Generate Answer')
const answerResult = await agent(`
You are a Nablarch expert answering a Japanese developer's question.

## Query
${QUERY}

## Section Content
${sectionsContent || '(no sections found)'}

## Task
Generate a Japanese answer following this format:

**結論**: Direct answer (1-2 sentences)
**根拠**: Code/config examples from sections
**注意点**: Constraints, common mistakes (omit if nothing applies)
参照: Only sections actually cited (file.json:sN format)

Stay within 500 tokens (up to 800 for complex questions).

Then verify: check that all Nablarch-specific claims are supported by the section content.
- API names, class names, configuration methods, behavior specs, constraints, parameters → must be in sections
- General Java/programming knowledge → OK to use without section support

If verification passes, output the answer as-is.
If verification fails, revise the answer to remove unsupported claims.

## Output Format (JSON)
{
  "answer_text": "<the final verified Japanese answer in markdown>",
  "verify_result": "PASS or FAIL",
  "issues": ["list of unsupported claims if FAIL, empty if PASS"],
  "used_sections": [{"ref": "<file.json:sN>", "reason": "<why used>"}],
  "unused_sections": [{"ref": "<file.json:sN>", "reason": "<why not used>"}]
}
`, { label: 'generate-answer', schema: {
  type: 'object',
  properties: {
    answer_text: { type: 'string' },
    verify_result: { type: 'string' },
    issues: { type: 'array', items: { type: 'string' } },
    used_sections: { type: 'array', items: { type: 'object', properties: { ref: { type: 'string' }, reason: { type: 'string' } }, required: ['ref', 'reason'] } },
    unused_sections: { type: 'array', items: { type: 'object', properties: { ref: { type: 'string' }, reason: { type: 'string' } }, required: ['ref', 'reason'] } }
  },
  required: ['answer_text', 'verify_result', 'issues', 'used_sections', 'unused_sections']
}})

log(`Answer generated. Verify result: ${answerResult.verify_result}`)

return {
  query: QUERY,
  step3: {
    selected_pages: searchResult.selected_pages,
    excluded_pages: searchResult.excluded_pages,
    selected_sections: searchResult.selected_sections,
    excluded_sections: searchResult.excluded_sections
  },
  step4: {
    read_sections: readSections
  },
  answer: answerResult.answer_text,
  verify_result: answerResult.verify_result,
  issues: answerResult.issues,
  step8: {
    answer_sections: {
      used: answerResult.used_sections,
      unused: answerResult.unused_sections
    }
  }
}
